var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"자, 방금 오븐에서 구운 에그타르트야.","JPN":"さあ、焼きたてのエッグタルトよ。","ENG":"Here, have some freshly baked egg tarts.","TWN":"請用，這是剛出爐的蛋塔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리 수도원의 몇 없는 자랑거리지. 모두들 좋아하는 메뉴였어.","JPN":"修道院の数少ない自慢でね。みんなが好きなメニューだったのよ。","ENG":"It’s one of the few specialties we have at the monastery. Everyone liked it.","TWN":"這是我們修道院少數的長處之一，大家都很喜歡吃。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맛의 비결은 갓 짜낸 우유와 첫 닭이 울 때 거둔 신선한 계란 정도일까.","JPN":"味の秘訣は搾りたての牛乳と、一番鶏が鳴いたときに集めた新鮮な卵くらいかしら。","ENG":"The secret to its taste is fresh milk, and eggs collected at the break of dawn.","TWN":"美味的秘訣應該是新鮮現擠的牛奶，和雞啼時下的第一顆新鮮雞蛋吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그래서 매일 새벽마다 에그타르트가 구워질 동안, 오븐 앞에 모여서 수다를 떨곤 했지.","JPN":"毎朝エッグタルトが焼けるまでの間、オーブンの前に集まっておしゃべりをしたものよ。","ENG":"We would all chat together near the oven every morning while the tarts were getting baked.","TWN":"每天清晨烤蛋塔時，大家都會聚在烤箱前閒話家常。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"나는 수도원이 계속 기억 속 그 모습 그대로 남아 있을 줄 알았어.","JPN":"私、修道院は私の記憶に残る姿のままでずっとあり続けるものと思っていたの。","ENG":"I thought the monastery would stay like that forever and ever.","TWN":"我以為修道院會一直停留在我記憶裡的樣子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"연구를 빙자해서 헛된 시도만 계속하고……","JPN":"研究を口実に愚かな試みばかりを続けながら……","ENG":"Keeping trying in vain, calling it research or whatever...","TWN":"但假借研究之名持續進行無謂的嘗試……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이슬 맺힌 단풍잎에서도 숨겨진 의미를 찾으려고 애쓰면서 말이야.","JPN":"露のついた紅葉の葉にさえ、隠された意味を探そうとしたりね。","ENG":"Trying to find hidden meaning even in a maple leaf with dew.","TWN":"就連結露的楓葉，也努力要從中找出隱藏的含意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"내가 죽고, 다른 사람이 내 역할을 대신해도, 그렇게 끝없이 실패만 거듭할 줄 알았지.","JPN":"私が死んで私の仕事を他の人がしたとしても、そうやってずっと失敗を繰り返していくだろうと思っていたわ。","ENG":"Even if I died and somebody else took my place, I was sure they'll continue making the same foolish failures...","TWN":"我原以為我死後，就算有其他人代替我的角色，也只是無止盡的失敗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하지만 지금은 전부 사라져 버렸어. 네 입 속에서 녹아 사라진 에그타르트처럼.","JPN":"でも今は全部消えてしまった。あなたの口の中で溶けるエッグタルトみたいにね。","ENG":"But now, they’re all gone. Just like the egg tart that melted inside your mouth.","TWN":"但現在已經全部消失不見，就像化在你口裡的蛋塔一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"마지막까지 나와 함께하겠다는 네 다짐은 언제까지 이어질까?","JPN":"最後まで私といると言ったあなたの誓いはいつまで続くかしら？","ENG":"So now I wonder. How long would your promise to be by my side last?","TWN":"你說要和我一起的決心可以持續到何時呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"충동적인 선택이었다고는 생각하지 않아. 그렇게 입이 가벼운 사람은 아니니까.","JPN":"衝動的な選択だったなんて思わないわ。そんなに口の軽い人じゃないもの。","ENG":"I know it wasn’t a spontaneous decision. You’re not the type of person to blurt something out like that.","TWN":"我不認為是衝動的決定，你不是那種輕易許下承諾的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그저…… 수렁에서 잡아 끌어 준 손이 사실은 진흙 대신 피투성이일 수도 있단 사실을 알아 둬.","JPN":"ただ……泥濘から引っ張り出してくれた手が実は泥ではなく血でまみれているかもしれないってことは知っておいてね。","ENG":"Just... keep that in mind. Sometimes things can be bloodier than you perceive them to be.","TWN":"只是……你記住，從泥沼裡伸出的手，未必是泥土，有可能是鮮血。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리 귀염둥이는 이미 각오했겠지만.","JPN":"かわい子ちゃんはもう覚悟していると思うけれど。","ENG":"But I’m sure my little cutie came prepared.","TWN":"不過我們小可愛應該有心理準備吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};